  1964→### 4.4.3 PM Schedule Management Service
  1965→
  1966→Handles manual PM modifications (drag-and-drop, manual reschedules) with full validation including Maximo status locks.
  1967→
  1968→```typescript
  1969→/**
  1970→ * Service for manual PM schedule modifications.
  1971→ * 
  1972→ * CRITICAL: All modifications MUST validate against Maximo status to prevent
  1973→ * race conditions with in-progress work orders. The PMEditValidator from the
  1974→ * Integration layer (Part 7) provides this validation.
  1975→ * 
  1976→ * Operational reality (Maximo) MUST override planning data (MMS).
  1977→ */
  1978→class PMScheduleManagementService {
  1979→  private pmEditValidator: PMEditValidator;  // From Part 7
  1980→  private auditLogger: AuditLogger;
  1981→  
  1982→  /**
  1983→   * Move a PM to a new date (e.g., from canvas drag-and-drop).
  1984→   * 
  1985→   * @throws MaximoLockError if PM is in-progress in Maximo
  1986→   * @throws ComplianceWindowError if new date is outside allowed window
  1987→   * @throws TrackConflictError if track is occupied on new date
  1988→   */
  1989→  async movePM(
  1990→    pmId: string,
  1991→    newTargetDate: Date,
  1992→    newTrackId: string | null,
  1993→    userId: string
  1994→  ): Promise<PMScheduleRecord> {
  1995→    
  1996→    // 1. CRITICAL: Validate Maximo status lock
  1997→    const editValidation = await this.pmEditValidator.validateEdit(pmId);
  1998→    
  1999→    if (!editValidation.valid) {
  2000→      throw new PMEditBlockedError(
  2001→        editValidation.reason,
  2002→        editValidation.message,
  2003→        {
  2004→          maximoStatus: editValidation.maximoStatus,
  2005→          maximoWonum: editValidation.maximoWonum,
  2006→          suggestion: editValidation.suggestion
  2007→        }
  2008→      );
  2009→    }
  2010→    
  2011→    // 2. Load PM with all relationships
  2012→    const pm = await this.db.query.pmSchedule.findFirst({
  2013→      where: eq(pmSchedule.id, pmId),
  2014→      with: {
  2015→        pmType: true,
  2016→        train: true,
  2017→        assignedTrack: true
  2018→      }
  2019→    });
  2020→    
  2021→    if (!pm) {
  2022→      throw new NotFoundError('PM not found');
  2023→    }
  2024→    
  2025→    // 3. Validate compliance window
  2026→    if (newTargetDate < pm.constraintStart || newTargetDate > pm.constraintEnd) {
  2027→      throw new ComplianceWindowError(
  2028→        `Target date ${newTargetDate.toISOString().split('T')[0]} is outside compliance window`,
  2029→        {
  2030→          constraintStart: pm.constraintStart,
  2031→          constraintEnd: pm.constraintEnd,
  2032→          requestedDate: newTargetDate
  2033→        }
  2034→      );
  2035→    }
  2036→    
  2037→    // 4. Validate track availability (if track specified)
  2038→    if (newTrackId) {
  2039→      const conflict = await this.checkTrackConflict(
  2040→        newTrackId,
  2041→        newTargetDate,
  2042→        pm.pmType.minTrackDays,
  2043→        pmId  // Exclude self from conflict check
  2044→      );
  2045→      
  2046→      if (conflict) {
  2047→        throw new TrackConflictError(
  2048→          `Track ${conflict.trackNumber} is occupied by ${conflict.conflictingPMCode}`,
  2049→          conflict
  2050→        );
  2051→      }
  2052→    }
  2053→    
  2054→    // 5. Capture old state for audit
  2055→    const oldState = {
  2056→      targetDate: pm.targetDate,
  2057→      assignedTrackId: pm.assignedTrackId
  2058→    };
  2059→    
  2060→    // 6. Update PM schedule
  2061→    const updatedPM = await this.db.transaction(async (tx) => {
  2062→      // Update main record
  2063→      const [updated] = await tx.update(pmSchedule)
  2064→        .set({
  2065→          targetDate: newTargetDate,
  2066→          assignedTrackId: newTrackId ?? pm.assignedTrackId,
  2067→          updatedAt: new Date()
  2068→        })
  2069→        .where(eq(pmSchedule.id, pmId))
  2070→        .returning();
  2071→      
  2072→      // Record in history table
  2073→      await tx.insert(pmScheduleHistory).values({
  2074→        pmScheduleId: pmId,
  2075→        changeType: 'RESCHEDULE',
  2076→        fieldName: 'targetDate',
  2077→        oldValue: oldState.targetDate.toISOString(),
  2078→        newValue: newTargetDate.toISOString(),
  2079→        changedBy: userId,
  2080→        reason: 'Manual reschedule via canvas'
  2081→      });
  2082→      
  2083→      if (newTrackId && newTrackId !== pm.assignedTrackId) {
  2084→        await tx.insert(pmScheduleHistory).values({
  2085→          pmScheduleId: pmId,
  2086→          changeType: 'TRACK_REASSIGNMENT',
  2087→          fieldName: 'assignedTrackId',
  2088→          oldValue: oldState.assignedTrackId,
  2089→          newValue: newTrackId,
  2090→          changedBy: userId,
  2091→          reason: 'Track reassignment via canvas'
  2092→        });
  2093→      }
  2094→      
  2095→      return updated;
  2096→    });
  2097→    
  2098→    // 7. Update shadow record for Maximo sync
  2099→    await this.updateShadowRecord(pmId, {
  2100→      syncStatus: 'PENDING',
  2101→      pendingChanges: {
  2102→        targetDate: newTargetDate.toISOString(),
  2103→        trackId: newTrackId
  2104→      }
  2105→    });
  2106→    
  2107→    // 8. Audit log
  2108→    await this.auditLogger.log({
  2109→      action: 'PM_RESCHEDULED',
  2110→      entityType: 'PM_SCHEDULE',
  2111→      entityId: pmId,
  2112→      userId,
  2113→      changes: {
  2114→        targetDate: { old: oldState.targetDate, new: newTargetDate },
  2115→        assignedTrackId: { old: oldState.assignedTrackId, new: newTrackId }
  2116→      }
  2117→    });
  2118→    
  2119→    return updatedPM;
  2120→  }
  2121→  
  2122→  /**
  2123→   * Get PM with all relationships for canvas display.
  2124→   */
  2125→  async getPM(pmId: string): Promise<PMScheduleWithRelations> {
  2126→    const pm = await this.db.query.pmSchedule.findFirst({
  2127→      where: eq(pmSchedule.id, pmId),
  2128→      with: {
  2129→        pmType: true,
  2130→        train: true,
  2131→        assignedTrack: true,
  2132→        assignedDepot: true
  2133→      }
  2134→    });
  2135→    
  2136→    if (!pm) {
  2137→      throw new NotFoundError('PM not found');
  2138→    }
  2139→    
  2140→    return pm;
  2141→  }
  2142→  
  2143→  /**
  2144→   * Check if a track has conflicts for the given date range.
  2145→   */
  2146→  private async checkTrackConflict(
  2147→    trackId: string,
  2148→    startDate: Date,
  2149→    durationDays: number,
  2150→    excludePmId?: string
  2151→  ): Promise<TrackConflict | null> {
  2152→    const endDate = addDays(startDate, durationDays);
  2153→    
  2154→    const conflictingPM = await this.db.query.pmSchedule.findFirst({
  2155→      where: and(
  2156→        eq(pmSchedule.assignedTrackId, trackId),
  2157→        excludePmId ? ne(pmSchedule.id, excludePmId) : undefined,
  2158→        or(
  2159→          // New PM overlaps existing PM's start
  2160→          and(
  2161→            lte(pmSchedule.targetDate, startDate),
  2162→            gte(sql`${pmSchedule.targetDate} + ${durationDays} * interval '1 day'`, startDate)
  2163→          ),
  2164→          // New PM overlaps existing PM's end
  2165→          and(
  2166→            lte(pmSchedule.targetDate, endDate),
  2167→            gte(sql`${pmSchedule.targetDate} + ${durationDays} * interval '1 day'`, startDate)
  2168→          )
  2169→        ),
  2170→        inArray(pmSchedule.status, ['SCHEDULED', 'IN_PROGRESS'])
  2171→      ),
  2172→      with: {
  2173→        pmType: true,
  2174→        train: true,
  2175→        assignedTrack: true
  2176→      }
  2177→    });
  2178→    
  2179→    if (conflictingPM) {
  2180→      return {
  2181→        trackId,
  2182→        trackNumber: conflictingPM.assignedTrack.trackNumber,
  2183→        conflictingPMId: conflictingPM.id,
  2184→        conflictingPMCode: conflictingPM.pmType.pmCode,
  2185→        conflictingTrainNumber: conflictingPM.train.trainNumber,
  2186→        conflictingDateRange: {
  2187→          start: conflictingPM.targetDate,
  2188→          end: addDays(conflictingPM.targetDate, conflictingPM.pmType.minTrackDays)
  2189→        }
  2190→      };
  2191→    }
  2192→    
  2193→    return null;
  2194→  }
  2195→}
