class StrategicPlanner {
  private constraintAggregation: ConstraintAggregationService;

  async generatePlan(
    fromBaseline: string | null
  ): Promise<StrategicPlanResult> {
    // 1. Load current fleet state
    const fleetState = await this.getFleetState();

    // 2. Project PM requirements for each train
    const pmRequirements = await this.projectPMRequirements(
      fleetState,
      this.config.horizonYears
    );

    // 3. Generate constraint envelopes for each quarter
    const envelopes = await this.generateEnvelopes();

    // 4. Run genetic algorithm
    const bestPlan = await this.runGeneticAlgorithm(
      pmRequirements,
      envelopes
    );

    // 5. Validate against constraint envelopes
    const validation = await this.validatePlan(bestPlan, envelopes);

    if (!validation.valid) {
      // Attempt repair
      const repairedPlan = await this.repairPlan(bestPlan, validation);
      return {
        plan: repairedPlan,
        validation: await this.validatePlan(repairedPlan, envelopes),
        metrics: this.calculateMetrics(repairedPlan)
      };
    }

    return {
      plan: bestPlan,
      validation,
      metrics: this.calculateMetrics(bestPlan)
    };
  }

  /**
   * Project PM requirements for all trains over the planning horizon.
   * 
   * CRITICAL: This implementation correctly handles:
   * 1. PM hierarchy (C4 satisfies C1/C2/C3 - resets their counters)
   * 2. Dual triggers (mileage OR time, whichever comes first)
   * 3. Recent velocity calculation for accurate projections
   * 4. Cascading projections (each PM feeds into next cycle)
   */
  private async projectPMRequirements(
    fleetState: FleetState,
    horizonYears: number
  ): Promise<PMRequirement[]> {
    const requirements: PMRequirement[] = [];
    const horizonEnd = addYears(new Date(), horizonYears);

    for (const train of fleetState.trains) {
      const trainRules = await this.getPMRulesForFleet(train.fleetId);
      const trainHistory = await this.getPMHistoryForTrain(train.id);

      // Calculate daily utilization for this train
      const dailyKm = this.calculateDailyUtilization(train, trainHistory);

      // Project all PM types for this train
      const trainProjections = await this.projectTrainPMs(
        train,
        trainRules,
        trainHistory,
        horizonEnd,
        dailyKm
      );

      requirements.push(...trainProjections);
    }

    return requirements;
  }

