  2810→    for (const [depotId, depotProjections] of byDepot) {
  2811→      const overloaded = depotProjections.filter(p => p.isOverloaded);
  2812→      const underutilized = depotProjections.filter(p => p.isUnderutilized);
  2813→      
  2814→      for (const overWeek of overloaded) {
  2815→        let remainingExcess = overWeek.required.total - overWeek.available.total;
  2816→        
  2817→        // Try each strategy in priority order
  2818→        for (const strategy of LEVELING_STRATEGIES) {
  2819→          if (remainingExcess <= 0) break;
  2820→          
  2821→          const adjustment = await this.tryStrategy(
  2822→            strategy,
  2823→            overWeek,
  2824→            underutilized,
  2825→            depotProjections,
  2826→            remainingExcess
  2827→          );
  2828→          
  2829→          if (adjustment) {
  2830→            adjustments.push(adjustment);
  2831→            remainingExcess -= adjustment.hoursAdjusted;
  2832→            
  2833→            // Update underutilized list if we used capacity
  2834→            if (adjustment.type === 'ADVANCE_PM' || adjustment.type === 'DEFER_PM') {
  2835→              this.updateUnderutilizedCapacity(underutilized, adjustment);
  2836→            }
  2837→          }
  2838→        }
  2839→        
  2840→        // If still overloaded, flag for manual review
  2841→        if (remainingExcess > 0) {
  2842→          adjustments.push({
  2843→            type: 'MANUAL_REVIEW',
  2844→            sourcePeriod: { start: overWeek.week, end: addDays(overWeek.week, 7) },
  2845→            hoursAdjusted: 0,
  2846→            affectedPMs: [],
  2847→            costImpact: 0,
  2848→            riskLevel: 'HIGH',
  2849→            reason: `Unable to resolve ${remainingExcess.toFixed(0)}h overload - requires manual intervention`
  2850→          });
  2851→        }
  2852→      }
  2853→    }
  2854→    
  2855→    return adjustments;
  2856→  }
  2857→  
  2858→  private async tryStrategy(
  2859→    strategy: LevelingStrategy,
  2860→    overloadedWeek: ManHourProjection,
  2861→    underutilizedWeeks: ManHourProjection[],
  2862→    allProjections: ManHourProjection[],
  2863→    excessHours: number
  2864→  ): Promise<ManHourAdjustment | null> {
  2865→    const maxHours = Math.min(strategy.maxHoursPerWeek, excessHours);
  2866→    
  2867→    switch (strategy.type) {
  2868→      case 'ADVANCE_PM':
  2869→      case 'DEFER_PM': {
  2870→        // Find candidate weeks
  2871→        const candidates = underutilizedWeeks
  2872→          .filter(w => {
  2873→            const weekDiff = differenceInWeeks(w.week, overloadedWeek.week);
  2874→            const direction = strategy.type === 'ADVANCE_PM' ? -1 : 1;
  2875→            return weekDiff * direction > 0 && Math.abs(weekDiff) <= 4;
  2876→          })
  2877→          .sort((a, b) => 
  2878→            Math.abs(differenceInWeeks(a.week, overloadedWeek.week)) -
  2879→            Math.abs(differenceInWeeks(b.week, overloadedWeek.week))
  2880→          );
  2881→        
  2882→        for (const candidate of candidates) {
  2883→          const availableCapacity = candidate.available.total - candidate.required.total;
  2884→          const shiftHours = Math.min(maxHours, availableCapacity * 0.8);
  2885→          
  2886→          if (shiftHours >= 8) {  // Minimum meaningful shift
  2887→            // Find PMs that can be shifted
  2888→            const shiftablePMs = await this.findShiftablePMs(
  2889→              overloadedWeek,
  2890→              candidate,
  2891→              shiftHours,
  2892→              strategy.type
  2893→            );
  2894→            
  2895→            if (shiftablePMs.length > 0) {
  2896→              const actualHours = shiftablePMs.reduce(
  2897→                (sum, pm) => sum + pm.estimatedHours, 0
  2898→              );
  2899→              
  2900→              return {
  2901→                type: strategy.type,
  2902→                sourcePeriod: { 
  2903→                  start: overloadedWeek.week, 
  2904→                  end: addDays(overloadedWeek.week, 7) 
  2905→                },
  2906→                targetPeriod: { 
  2907→                  start: candidate.week, 
  2908→                  end: addDays(candidate.week, 7) 
  2909→                },
  2910→                hoursAdjusted: actualHours,
  2911→                affectedPMs: shiftablePMs.map(pm => pm.id),
  2912→                costImpact: actualHours * this.getBaseRate() * (strategy.costMultiplier - 1),
  2913→                riskLevel: strategy.riskLevel,
  2914→                reason: `${strategy.type === 'DEFER_PM' ? 'Defer' : 'Advance'} ${actualHours.toFixed(0)}h from Week ${format(overloadedWeek.week, 'ww')} to Week ${format(candidate.week, 'ww')}`
  2915→              };
  2916→            }
  2917→          }
  2918→        }
  2919→        return null;
  2920→      }
  2921→      
  2922→      case 'ADD_OVERTIME': {
  2923→        const availableOvertime = overloadedWeek.available.overtime;
  2924→        const overtimeHours = Math.min(maxHours, availableOvertime);
  2925→        
  2926→        if (overtimeHours >= 4) {
  2927→          return {
  2928→            type: 'ADD_OVERTIME',
  2929→            sourcePeriod: { 
  2930→              start: overloadedWeek.week, 
  2931→              end: addDays(overloadedWeek.week, 7) 
  2932→            },
  2933→            targetPeriod: { 
  2934→              start: overloadedWeek.week, 
  2935→              end: addDays(overloadedWeek.week, 7) 
  2936→            },
  2937→            hoursAdjusted: overtimeHours,
  2938→            affectedPMs: [],
  2939→            costImpact: overtimeHours * this.getBaseRate() * (strategy.costMultiplier - 1),
  2940→            riskLevel: strategy.riskLevel,
  2941→            reason: `Add ${overtimeHours.toFixed(0)}h overtime in Week ${format(overloadedWeek.week, 'ww')}`
  2942→          };
  2943→        }
  2944→        return null;
  2945→      }
  2946→      
  2947→      case 'CROSS_DEPOT': {
  2948→        // Find other depots with capacity
  2949→        const otherDepots = await this.findDepotsWithCapacity(
  2950→          overloadedWeek.week,
  2951→          maxHours
  2952→        );
  2953→        
  2954→        if (otherDepots.length > 0) {
  2955→          const best = otherDepots[0];
  2956→          return {
  2957→            type: 'CROSS_DEPOT',
  2958→            sourcePeriod: { 
  2959→              start: overloadedWeek.week, 
  2960→              end: addDays(overloadedWeek.week, 7) 
  2961→            },
  2962→            targetPeriod: { 
  2963→              start: overloadedWeek.week, 
  2964→              end: addDays(overloadedWeek.week, 7) 
  2965→            },
  2966→            hoursAdjusted: best.availableHours,
  2967→            affectedPMs: [],
  2968→            costImpact: best.availableHours * this.getBaseRate() * (strategy.costMultiplier - 1),
  2969→            riskLevel: strategy.riskLevel,
  2970→            reason: `Request ${best.availableHours.toFixed(0)}h support from ${best.depotName} in Week ${format(overloadedWeek.week, 'ww')}`
  2971→          };
  2972→        }
  2973→        return null;
  2974→      }
  2975→      
  2976→      case 'ADD_CONTRACTOR': {
  2977→        return {
  2978→          type: 'ADD_CONTRACTOR',
  2979→          sourcePeriod: { 
  2980→            start: overloadedWeek.week, 
  2981→            end: addDays(overloadedWeek.week, 7) 
  2982→          },
  2983→          targetPeriod: { 
  2984→            start: overloadedWeek.week, 
  2985→            end: addDays(overloadedWeek.week, 7) 
  2986→          },
  2987→          hoursAdjusted: maxHours,
  2988→          affectedPMs: [],
  2989→          costImpact: maxHours * this.getBaseRate() * (strategy.costMultiplier - 1),
  2990→          riskLevel: strategy.riskLevel,
  2991→          reason: `Engage contractor for ${maxHours.toFixed(0)}h in Week ${format(overloadedWeek.week, 'ww')}`
  2992→        };
  2993→      }
  2994→    }
  2995→    
  2996→    return null;
  2997→  }
  2998→}
  2999→```
