## 4.6 Man-hour Leveling Engine

### 4.6.1 Purpose

Project workforce requirements and generate adjustment recommendations to balance workload across time periods.

### 4.6.2 Implementation

```typescript
interface LevelingStrategy {
  type: 'DEFER_PM' | 'ADVANCE_PM' | 'ADD_OVERTIME' | 'CROSS_DEPOT' | 'ADD_CONTRACTOR';
  priority: number;
  maxHoursPerWeek: number;
  costMultiplier: number;
  riskLevel: 'NONE' | 'LOW' | 'MEDIUM' | 'HIGH';
}

const LEVELING_STRATEGIES: LevelingStrategy[] = [
  { type: 'ADVANCE_PM', priority: 1, maxHoursPerWeek: 40, costMultiplier: 1.1, riskLevel: 'LOW' },
  { type: 'DEFER_PM', priority: 2, maxHoursPerWeek: 40, costMultiplier: 1.05, riskLevel: 'LOW' },
  { type: 'ADD_OVERTIME', priority: 3, maxHoursPerWeek: 80, costMultiplier: 1.5, riskLevel: 'NONE' },
  { type: 'CROSS_DEPOT', priority: 4, maxHoursPerWeek: 60, costMultiplier: 1.3, riskLevel: 'MEDIUM' },
  { type: 'ADD_CONTRACTOR', priority: 5, maxHoursPerWeek: 100, costMultiplier: 2.0, riskLevel: 'MEDIUM' },
];

class ManHourLevelingEngine {
  private readonly TARGET_UTILIZATION = 0.85;
  private readonly MIN_UTILIZATION = 0.70;
  private readonly MAX_UTILIZATION = 1.00;

  async generateProjections(
    horizonWeeks: number = 12,
    depotIds?: string[]
  ): Promise<LevelingResult> {
    const runId = crypto.randomUUID();

    // 1. Calculate raw projections
    const rawProjections = await this.calculateRawProjections(
      horizonWeeks,
      depotIds
    );

    // 2. Identify imbalances
    const imbalances = this.identifyImbalances(rawProjections);

    // 3. Generate adjustments using multiple strategies
    const adjustments = await this.generateAdjustments(
      rawProjections,
      imbalances
    );

    // 4. Apply adjustments to get leveled projections
    const leveledProjections = this.applyAdjustments(
      rawProjections,
      adjustments
    );

    // 5. Calculate metrics
    const originalMetrics = this.calculateMetrics(rawProjections);
    const leveledMetrics = this.calculateMetrics(leveledProjections);

    // 6. Persist
    await this.persistProjections(runId, rawProjections, leveledProjections, adjustments);

    // 7. Broadcast update
    await this.websocketHub.broadcast('manhour:updated', {
      runId,
      summary: { originalMetrics, leveledMetrics }
    });

    return {
      projectionRunId: runId,
      generatedAt: new Date(),
      horizonWeeks,
      original: { projections: rawProjections, metrics: originalMetrics },
      leveled: { projections: leveledProjections, metrics: leveledMetrics },
      adjustments,
      improvement: {
        utilizationDelta: leveledMetrics.avgUtilization - originalMetrics.avgUtilization,
        overloadedWeeksReduced: originalMetrics.overloadedWeeks - leveledMetrics.overloadedWeeks,
        totalCostImpact: adjustments.reduce((sum, a) => sum + a.costImpact, 0)
      }
    };
  }

  private async generateAdjustments(
    projections: ManHourProjection[],
    imbalances: Imbalance[]
  ): Promise<ManHourAdjustment[]> {
    const adjustments: ManHourAdjustment[] = [];
    const byDepot = this.groupByDepot(projections);

    for (const [depotId, depotProjections] of byDepot) {
      const overloaded = depotProjections.filter(p => p.isOverloaded);
      const underutilized = depotProjections.filter(p => p.isUnderutilized);

      for (const overWeek of overloaded) {
        let remainingExcess = overWeek.required.total - overWeek.available.total;

        // Try each strategy in priority order
        for (const strategy of LEVELING_STRATEGIES) {
          if (remainingExcess <= 0) break;

          const adjustment = await this.tryStrategy(
            strategy,
            overWeek,
            underutilized,
            depotProjections,
            remainingExcess
          );

          if (adjustment) {
            adjustments.push(adjustment);
            remainingExcess -= adjustment.hoursAdjusted;

            // Update underutilized list if we used capacity
            if (adjustment.type === 'ADVANCE_PM' || adjustment.type === 'DEFER_PM') {
              this.updateUnderutilizedCapacity(underutilized, adjustment);
            }
          }
        }

        // If still overloaded, flag for manual review
        if (remainingExcess > 0) {
          adjustments.push({
            type: 'MANUAL_REVIEW',
            sourcePeriod: { start: overWeek.week, end: addDays(overWeek.week, 7) },
            hoursAdjusted: 0,
            affectedPMs: [],
            costImpact: 0,
            riskLevel: 'HIGH',
            reason: `Unable to resolve ${remainingExcess.toFixed(0)}h overload - requires manual intervention`
          });
        }
      }
    }

    return adjustments;
  }

  private async tryStrategy(
    strategy: LevelingStrategy,
    overloadedWeek: ManHourProjection,
    underutilizedWeeks: ManHourProjection[],
    allProjections: ManHourProjection[],
    excessHours: number
  ): Promise<ManHourAdjustment | null> {
    const maxHours = Math.min(strategy.maxHoursPerWeek, excessHours);

    switch (strategy.type) {
      case 'ADVANCE_PM':
      case 'DEFER_PM': {
        // Find candidate weeks
        const candidates = underutilizedWeeks
          .filter(w => {
            const weekDiff = differenceInWeeks(w.week, overloadedWeek.week);
            const direction = strategy.type === 'ADVANCE_PM' ? -1 : 1;
            return weekDiff * direction > 0 && Math.abs(weekDiff) <= 4;
          })
          .sort((a, b) => 
            Math.abs(differenceInWeeks(a.week, overloadedWeek.week)) -
            Math.abs(differenceInWeeks(b.week, overloadedWeek.week))
          );

        for (const candidate of candidates) {
          const availableCapacity = candidate.available.total - candidate.required.total;
          const shiftHours = Math.min(maxHours, availableCapacity * 0.8);

          if (shiftHours >= 8) {  // Minimum meaningful shift
            // Find PMs that can be shifted
            const shiftablePMs = await this.findShiftablePMs(
              overloadedWeek,
              candidate,
              shiftHours,
              strategy.type
            );

            if (shiftablePMs.length > 0) {
              const actualHours = shiftablePMs.reduce(
                (sum, pm) => sum + pm.estimatedHours, 0
              );

              return {
                type: strategy.type,
                sourcePeriod: { 
                  start: overloadedWeek.week, 
                  end: addDays(overloadedWeek.week, 7) 
                },
                targetPeriod: { 
                  start: candidate.week, 
                  end: addDays(candidate.week, 7) 
                },
                hoursAdjusted: actualHours,
                affectedPMs: shiftablePMs.map(pm => pm.id),
                costImpact: actualHours * this.getBaseRate() * (strategy.costMultiplier - 1),
                riskLevel: strategy.riskLevel,
                reason: `${strategy.type === 'DEFER_PM' ? 'Defer' : 'Advance'} ${actualHours.toFixed(0)}h from Week ${format(overloadedWeek.week, 'ww')} to Week ${format(candidate.week, 'ww')}`
              };
            }
          }
        }
        return null;
      }

      case 'ADD_OVERTIME': {
        const availableOvertime = overloadedWeek.available.overtime;
        const overtimeHours = Math.min(maxHours, availableOvertime);

        if (overtimeHours >= 4) {
          return {
            type: 'ADD_OVERTIME',
            sourcePeriod: { 
              start: overloadedWeek.week, 
              end: addDays(overloadedWeek.week, 7) 
            },
            targetPeriod: { 
              start: overloadedWeek.week, 
              end: addDays(overloadedWeek.week, 7) 
            },
            hoursAdjusted: overtimeHours,
            affectedPMs: [],
            costImpact: overtimeHours * this.getBaseRate() * (strategy.costMultiplier - 1),
            riskLevel: strategy.riskLevel,
            reason: `Add ${overtimeHours.toFixed(0)}h overtime in Week ${format(overloadedWeek.week, 'ww')}`
          };
        }
        return null;
      }

      case 'CROSS_DEPOT': {
        // Find other depots with capacity
        const otherDepots = await this.findDepotsWithCapacity(
          overloadedWeek.week,
          maxHours
        );

        if (otherDepots.length > 0) {
          const best = otherDepots[0];
          return {
            type: 'CROSS_DEPOT',
            sourcePeriod: { 
              start: overloadedWeek.week, 
              end: addDays(overloadedWeek.week, 7) 
            },
            targetPeriod: { 
              start: overloadedWeek.week, 
              end: addDays(overloadedWeek.week, 7) 
            },
            hoursAdjusted: best.availableHours,
            affectedPMs: [],
            costImpact: best.availableHours * this.getBaseRate() * (strategy.costMultiplier - 1),
            riskLevel: strategy.riskLevel,
            reason: `Request ${best.availableHours.toFixed(0)}h support from ${best.depotName} in Week ${format(overloadedWeek.week, 'ww')}`
          };
        }
        return null;
      }

      case 'ADD_CONTRACTOR': {
        return {
          type: 'ADD_CONTRACTOR',
          sourcePeriod: { 
            start: overloadedWeek.week, 
            end: addDays(overloadedWeek.week, 7) 
          },
          targetPeriod: { 
            start: overloadedWeek.week, 
            end: addDays(overloadedWeek.week, 7) 
          },
          hoursAdjusted: maxHours,
          affectedPMs: [],
          costImpact: maxHours * this.getBaseRate() * (strategy.costMultiplier - 1),
          riskLevel: strategy.riskLevel,
          reason: `Engage contractor for ${maxHours.toFixed(0)}h in Week ${format(overloadedWeek.week, 'ww')}`
        };
      }
    }

    return null;
  }
}
