## 4.8 Drift Monitor Service

### 4.8.1 Purpose

Compare actual state against published baseline, calculate drift metrics, and alert when thresholds are exceeded.

### 4.8.2 Implementation

```typescript
interface DriftThresholds {
  mileageDriftPct: number;        // 5.0
  scheduleDriftDays: number;      // 14
  fleetDriftTrainCount: number;   // 5
}

class DriftMonitorService {
  private readonly thresholds: DriftThresholds = {
    mileageDriftPct: 5.0,
    scheduleDriftDays: 14,
    fleetDriftTrainCount: 5
  };

  /**
   * Run nightly drift analysis
   */
  async runDriftAnalysis(): Promise<DriftAnalysisResult> {
    const baseline = await this.getPublishedBaseline();
    if (!baseline) {
      this.logger.info('No published baseline, skipping drift analysis');
      return { skipped: true, reason: 'No published baseline' };
    }

    const analysisDate = new Date();
    const trainAnalyses: TrainDriftAnalysis[] = [];
    const alerts: DriftAlert[] = [];

    // Analyze each train
    const trains = await this.db.query.trains.findMany({
      where: eq(trains.active, true)
    });

    for (const train of trains) {
      const analysis = await this.analyzeTrainDrift(train, baseline, analysisDate);
      trainAnalyses.push(analysis);

      // Check thresholds
      if (analysis.requiresReplan) {
        alerts.push({
          trainId: train.id,
          trainNumber: train.trainNumber,
          severity: 'HIGH',
          type: 'REPLAN_REQUIRED',
          message: analysis.replanReason,
          metrics: {
            mileageDriftPct: analysis.mileageDriftPct,
            avgPmDriftDays: analysis.avgPmDriftDays
          }
        });
      } else if (Math.abs(analysis.mileageDriftPct) > this.thresholds.mileageDriftPct * 0.7) {
        alerts.push({
          trainId: train.id,
          trainNumber: train.trainNumber,
          severity: 'MEDIUM',
          type: 'APPROACHING_THRESHOLD',
          message: `Mileage drift at ${analysis.mileageDriftPct.toFixed(1)}% (threshold: ${this.thresholds.mileageDriftPct}%)`,
          metrics: {
            mileageDriftPct: analysis.mileageDriftPct
          }
        });
      }

      // Persist analysis
      await this.persistDriftAnalysis(analysis, baseline.id, analysisDate);
    }

    // Fleet-level analysis
    const trainsRequiringReplan = trainAnalyses.filter(a => a.requiresReplan).length;

    if (trainsRequiringReplan >= this.thresholds.fleetDriftTrainCount) {
      alerts.push({
        severity: 'CRITICAL',
        type: 'FLEET_REPLAN_RECOMMENDED',
        message: `${trainsRequiringReplan} trains require replanning - consider strategic replan`,
        metrics: {
          affectedTrains: trainsRequiringReplan
        }
      });
    }

    // Send alerts
    if (alerts.length > 0) {
      await this.sendDriftAlerts(alerts);
    }

    // Broadcast to canvas
    await this.websocketHub.broadcast('drift:updated', {
      baselineId: baseline.id,
      analysisDate,
      summary: {
        totalTrains: trains.length,
        trainsWithDrift: trainAnalyses.filter(a => Math.abs(a.mileageDriftPct) > 1).length,
        trainsRequiringReplan,
        avgFleetDriftPct: trainAnalyses.reduce((sum, a) => sum + a.mileageDriftPct, 0) / trainAnalyses.length
      },
      alerts
    });

    return {
      skipped: false,
      baselineId: baseline.id,
      analysisDate,
      trainAnalyses,
      alerts
    };
  }

  private async analyzeTrainDrift(
    train: Train,
    baseline: PlanBaseline,
    analysisDate: Date
  ): Promise<TrainDriftAnalysis> {
    // Get baseline projection for today
    const baselineProjection = await this.db.query.baselineMileageProjection.findFirst({
      where: and(
        eq(baselineMileageProjection.baselineId, baseline.id),
        eq(baselineMileageProjection.trainId, train.id),
        lte(baselineMileageProjection.projectionDate, analysisDate)
      ),
      orderBy: desc(baselineMileageProjection.projectionDate)
    });

    // Calculate mileage drift
    const baselineKm = baselineProjection?.projectedCumulativeKm || train.currentMileageKm;
    const actualKm = train.currentMileageKm;
    const mileageDriftKm = actualKm - baselineKm;
    const mileageDriftPct = (mileageDriftKm / baselineKm) * 100;

    // Get baseline PM schedule
    const baselinePMs = await this.db.query.baselinePmSchedule.findMany({
      where: and(
        eq(baselinePmSchedule.baselineId, baseline.id),
        eq(baselinePmSchedule.trainId, train.id),
        gte(baselinePmSchedule.projectedDate, analysisDate)
      )
    });

    // Get current PM schedule
    const currentPMs = await this.db.query.pmSchedule.findMany({
      where: and(
        eq(pmSchedule.trainId, train.id),
        isNull(pmSchedule.scenarioId),
        inArray(pmSchedule.status, ['SCHEDULED', 'IN_PROGRESS']),
        gte(pmSchedule.targetDate, analysisDate)
      )
    });

    // Calculate PM drift
    const pmDrifts: PMDrift[] = [];

    for (const baselinePM of baselinePMs) {
      const currentPM = currentPMs.find(
        p => p.pmTypeId === baselinePM.pmTypeId
      );

      if (currentPM) {
        const driftDays = differenceInDays(
          new Date(currentPM.targetDate),
          new Date(baselinePM.projectedDate)
        );

        pmDrifts.push({
          pmTypeId: baselinePM.pmTypeId,
          baselineDate: baselinePM.projectedDate,
          currentDate: currentPM.targetDate,
          driftDays,
          direction: driftDays > 0 ? 'LATER' : driftDays < 0 ? 'EARLIER' : 'ON_TRACK'
        });
      }
    }

    const avgPmDriftDays = pmDrifts.length > 0
      ? pmDrifts.reduce((sum, p) => sum + Math.abs(p.driftDays), 0) / pmDrifts.length
      : 0;

    const maxPmDriftDays = pmDrifts.length > 0
      ? Math.max(...pmDrifts.map(p => Math.abs(p.driftDays)))
      : 0;

    // Determine if replan required
    const requiresReplan = 
      Math.abs(mileageDriftPct) > this.thresholds.mileageDriftPct ||
      maxPmDriftDays > this.thresholds.scheduleDriftDays;

    let replanReason: string | undefined;
    if (requiresReplan) {
      const reasons: string[] = [];
      if (Math.abs(mileageDriftPct) > this.thresholds.mileageDriftPct) {
        reasons.push(`Mileage drift ${mileageDriftPct.toFixed(1)}% exceeds ${this.thresholds.mileageDriftPct}% threshold`);
      }
      if (maxPmDriftDays > this.thresholds.scheduleDriftDays) {
        reasons.push(`PM schedule drift ${maxPmDriftDays} days exceeds ${this.thresholds.scheduleDriftDays} day threshold`);
      }
      replanReason = reasons.join('; ');
    }

    return {
      trainId: train.id,
      trainNumber: train.trainNumber,
      baselineProjectedKm: baselineKm,
      actualKm,
      mileageDriftKm,
      mileageDriftPct,
      pmDrifts,
      avgPmDriftDays,
      maxPmDriftDays,
      requiresReplan,
      replanReason
    };
  }
}
